import React, { useRef } from 'react';
import { useIntroAnimation } from '../useAnimations'; 
import './Intro.css';

// 부모(App.js)로부터 onStart 함수를 받아옵니다.
function Intro({ onStart }) {
  const posterARef = useRef(null);
  const posterBRef = useRef(null);
  const titleImageRef = useRef(null); // Ref 이름을 직관적으로 변경
  const buttonRef = useRef(null);

  // 기존 애니메이션 로직 그대로 유지 (titleImageRef로 변경)
  useIntroAnimation(posterARef, posterBRef, titleImageRef, buttonRef);

  return (
    <div className="intro-container">
      {/* 배경 이미지들 */}
      <img ref={posterARef} src="/assets/posterA.png" className="poster-bg poster-a" alt="배경 A" />
      <img ref={posterBRef} src="/assets/posterB.png" className="poster-bg poster-b" alt="배경 B" />
      
      <div className="content-wrapper">
        {/* 텍스트 대신 제목 이미지를 사용합니다. */}
        {/* Ref와 클래스명을 변경했습니다. CSS에서 스타일을 조정해야 합니다. */}
        <img 
          ref={titleImageRef} 
          src="/assets/intro_title.png" // 실제 제목 이미지 경로로 수정하세요
          alt="당신의 단종은 누구인가요?" 
          className="intro-title-img" 
        />
        
        {/* 버튼 클릭 시 App.js의 스크롤 함수(onStart)를 실행합니다. */}
        <button 
          ref={buttonRef} 
          className="start-button" 
          onClick={onStart} 
        >
          Next
        </button>
      </div>
    </div>
  );
}

export default Intro;