import React, { useState, useMemo } from 'react';
import './InstagramScene.css';

function InstagramScene({ onComplete }) {
  const [isLiked, setIsLiked] = useState(false);
  const [showFireworks, setShowFireworks] = useState(false);

  // 1. 메가 파티클 데이터 생성 (200개로 증폭!)
  const particles = useMemo(() => 
    Array.from({ length: 200 }).map((_, i) => ({
      // 💥 초광범위: 사방 500px까지 (총 1000px 범위)
      tx: (Math.random() - 0.5) * 1000 + "px", 
      ty: (Math.random() - 0.5) * 1000 + "px",
      
      // ✨ 다양한 크기 (잔상 효과 유도)
      size: Math.random() * 6 + 2 + "px",       
      
      // ⏳ 다양한 지속 시간 (1s ~ 3s 사이)
      duration: Math.random() * 2 + 1.0 + "s",  
      delay: Math.random() * 0.3 + "s",         
      
      // 🌈 다채로운 프리미엄 색상 팔레트
      color: [
        '#FF5E5E', '#FFD700', '#FF1493', '#00FF7F', '#FF69B4', '#FFFFFF', // 기존
        '#7efff5', '#3ae374', '#fff200', '#ff9f1a', '#fff', '#ff3838'      // 네온 & 비비드 추가
      ][i % 12]
    })), []
  );

/* InstagramScene.js 수정본 */

const handleLikeClick = () => {
  if (!isLiked) {
    setIsLiked(true);
    setShowFireworks(true);
    
    // 1. 폭죽이 터지고 나서 약 2.5초 뒤에 자동으로 다음 페이지로 스크롤
    // 폭죽의 여운을 즐길 수 있도록 setTimeout을 사용합니다.
    setTimeout(() => {
      if (onComplete) onComplete();
    }, 1500); // 2.5초 후 실행 (취향에 따라 3000으로 조절 가능)

    // 2. 폭죽 애니메이션 레이어는 4초 뒤에 제거 (기존 유지)
    setTimeout(() => {
      setShowFireworks(false);
    }, 4000);
  }
};

  return (
    <div className="instagram-interaction-container">
      {/* 배경 */}
      <img src="/assets/background.png" alt="배경" className="interaction-bg" />

      {/* 2층: 메가 폭죽 레이어 */}
      {showFireworks && (
        <div className="fireworks-layer">
          {particles.map((p, i) => (
            <div 
              key={i} 
              className="particle" 
              style={{ 
                '--tx': p.tx, 
                '--ty': p.ty,
                '--duration': p.duration,
                '--delay': p.delay,
                width: p.size,
                height: p.size,
                backgroundColor: p.color,
                // 빛나는 효과(Glow) 강화
                boxShadow: `0 0 15px ${p.color}, 0 0 5px white` 
              }} 
            />
          ))}
        </div>
      )}

      {/* 3층: 사진 */}
      <div className="instagram-overlay" onClick={handleLikeClick}>
        <img 
          src={isLiked ? "/assets/insta_after.png" : "/assets/insta_before.png"} 
          alt="인스타 콘텐츠" 
          className="insta-content-img"
        />
      </div>
    </div>
  );
}

export default InstagramScene;